func dispatchW_p(slot uint32, recv unsafe.Pointer) unsafe.Pointer {
	var pw [0]unsafe.Pointer
	var sw [0]uint64
	var rpw [1]unsafe.Pointer
	var rsw [0]uint64
	if core := slotPoolW_p[slot]; core != nil {
		core(recv, pw[:], sw[:], rpw[:], rsw[:])
	}
	return rpw[0]
}

